body.script:
let currentPos = null;
const historyEl = document.getElementById('history');

function addHistory(text){
  const li=document.createElement('li');
  li.textContent = new Date().toLocaleTimeString('pt-BR')+' - '+text;
  historyEl.prepend(li);
}

document.getElementById('btnGeo').onclick = ()=>{
  if(!navigator.geolocation){
    alert('Geolocalização indisponível');
    return;
  }
  navigator.geolocation.getCurrentPosition(p=>{
    currentPos = {lat:p.coords.latitude, lng:p.coords.longitude};
    document.getElementById('geoInfo').textContent = `Lat ${currentPos.lat.toFixed(6)} | Lng ${currentPos.lng.toFixed(6)}`;
    document.getElementById('map').textContent = 'Localização capturada com sucesso';
    addHistory('Geolocalização capturada');
  }, ()=>{
    alert('Não foi possível obter a localização');
  }, {enableHighAccuracy:true, timeout:10000});
};

document.getElementById('btnQR').onclick = ()=>{
  addHistory('QR Code validado (simulado)');
  alert('Validação de QR simulada no MVP');
};

document.getElementById('btnCheckin').onclick = ()=>{
  if(!currentPos){
    alert('Capture a geolocalização primeiro');
    return;
  }
  document.getElementById('checkStatus').textContent = 'Check-in registrado com sucesso';
  document.getElementById('m2').textContent = String(Number(document.getElementById('m2').textContent)+1);
  addHistory('Check-in registrado');
};

document.getElementById('btnSign').onclick = ()=>{
  const name = document.getElementById('sigName').value.trim();
  if(!name){
    alert('Informe o nome para assinatura');
    return;
  }
  document.getElementById('signStatus').textContent = `Assinado por ${name}`;
  document.getElementById('m3').textContent = String(Math.max(0, Number(document.getElementById('m3').textContent)-1));
  addHistory('Documento assinado por '+name);
};

addHistory('Sistema iniciado');

if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker.register('service-worker.js');
  });
}
